class Solution:
    def isLongPressedName(self, name: str, typed: str) -> bool:
        i = 0
        for c in typed:
            if i < len(name) and c == name[i]:
                i += 1
            elif typed.count(c) > name.count(c):
                return False
        return i == len(name)
